    visual_description: "A concept-web showing how the printing press in colonial India fed the vernacular press, social reform debates and the growth of nationalism.",
    svg_diagrams: [svg("sst_ch5_india_print_diagram", "Print Culture in Colonial India", `<text x="20" y="26" font-weight="bold">Print in Colonial India</text><rect x="200" y="45" width="160" height="40" fill="#e8f0fe" stroke="#333"/><text x="208" y="70">Printing press arrives</text><line x1="240" y1="85" x2="120" y2="130" stroke="#333"/><line x1="280" y1="85" x2="280" y2="130" stroke="#333"/><line x1="320" y1="85" x2="440" y2="130" stroke="#333"/><rect x="40" y="130" width="150" height="40" fill="#fff3cd" stroke="#333"/><text x="48" y="155">Vernacular press</text><rect x="205" y="130" width="150" height="40" fill="#fff3cd" stroke="#333"/><text x="213" y="155">Reform debates</text><rect x="370" y="130" width="150" height="40" fill="#d4edda" stroke="#333"/><text x="378" y="155">Nationalism</text>`)],
    when_to_use_this_method: { use_this_when: ["Questions on how print helped Indian social and religious reform", "Questions on the role of the vernacular press and colonial censorship (Vernacular Press Act 1878)", "Source questions on print and the rise of nationalism"], use_other_when: ["Questions on Gutenberg and Europe — use print-revolution", "Questions specifically on women readers/reform — use social-changes"] },
    edge_cases: [ { case: "Thinking the British freely encouraged the Indian press", value: "After 1857 the colonial government grew wary; the Vernacular Press Act of 1878 gave it sweeping powers to censor and silence nationalist Indian-language newspapers", reasoning: "Print became a tool of nationalist criticism, so the state tried to control it", where_it_appears: "3-mark 'How did the colonial state try to control the press?' answers" } ],
    video_script_hooks: { opening_hook: "When the printing press reached India, it did far more than copy books — it gave reformers and nationalists a voice the colonial rulers could not easily silence.", concept_reveal: "Cheap vernacular print spread reform debates and national ideas so widely that the British answered with censorship laws like the Vernacular Press Act." },
