    svg_diagrams: [svg("sst_ch5_print_revolution_diagram", "The Print Revolution", `<text x="20" y="26" font-weight="bold">Print Revolution: Gutenberg onward</text><line x1="30" y1="110" x2="530" y2="110" stroke="#333"/><circle cx="80" cy="110" r="5" fill="#333"/><text x="55" y="100" font-size="11">1450s</text><text x="40" y="140" font-size="11">Movable type</text><circle cx="230" cy="110" r="5" fill="#333"/><text x="205" y="100" font-size="11">1517</text><text x="185" y="140" font-size="11">Reformation (Luther)</text><circle cx="390" cy="110" r="5" fill="#333"/><text x="365" y="100" font-size="11">1700s</text><text x="345" y="140" font-size="11">Reading mania</text><circle cx="500" cy="110" r="5" fill="#333"/><text x="465" y="160" font-size="11">Print capitalism</text>`)],
    when_to_use_this_method: { use_this_when: ["Questions on Gutenberg's invention and the first printed books (Bible)", "Questions linking print to the Protestant Reformation and the Church's loss of control", "Source questions on 'reading mania' and the fear of print"], use_other_when: ["Questions on Indian print and censorship — use india-print", "Questions on women/reform — use social-changes"] },
    edge_cases: [ { case: "Thinking everyone welcomed the printing press", value: "Many feared print: religious authorities worried it would spread rebellious or irreligious ideas, and the Church drew up an Index of Prohibited Books from 1558", reasoning: "Print let ordinary people read and interpret texts (like the Bible) themselves, weakening the authority of the Church", where_it_appears: "5-mark 'Why did some fear the coming of print?' answers" } ],
    video_script_hooks: { opening_hook: "In the 1450s a goldsmith named Gutenberg built a machine that would shake the power of kings and the Church — the printing press.", concept_reveal: "Movable type made books cheap and plentiful, fuelling the Reformation and a 'reading mania' that spread new ideas faster than ever before." },
