    edge_cases: [ { case: "Calling Bhakra-Nangal a 'single-purpose' dam", value: "Multipurpose projects serve several purposes at once — irrigation, hydroelectricity, flood control, water supply, navigation; Bhakra-Nangal (Sutlej) and Hirakud (Mahanadi) are examples.", reasoning: "'Multipurpose' is the defining feature Nehru called 'temples of modern India'.", where_it_appears: "Definition/example questions." }, { case: "Assuming dams only help and never harm", value: "Dams cause displacement, submergence of forests, sedimentation, reduced downstream flow and even induced seismicity — sparking movements like Narmada Bachao Andolan.", reasoning: "NCERT presents a balanced benefits-vs-problems view.", where_it_appears: "5-mark 'critically evaluate' questions." } ],
    video_script_hooks: { opening_hook: "Nehru called India's great dams 'the temples of modern India' — but for the families they displaced, they were anything but sacred.", concept_reveal: "Multipurpose river projects deliver irrigation, power and flood control from one dam, yet they also submerge land, displace people and disturb river ecology." },
