    edge_cases: [ { case: "Rice and wheat grow in the same season", value: "Rice is a kharif crop (sown with the monsoon, Jun-Sep); wheat is a rabi crop (sown in winter, Oct-Dec, harvested in spring)", reasoning: "Rice needs high temperature and heavy rain; wheat needs cool growing season and bright sunshine at ripening", where_it_appears: "1-mark fill/MCQ" }, { case: "Jute and cotton are both 'fibre' so interchangeable", value: "Cotton grows on black soil of the Deccan plateau; jute grows on well-drained fertile alluvial soil in the flood plains of West Bengal/Bihar/Assam", reasoning: "Different soils and climates; jute is the 'golden fibre' of the eastern flood plains", where_it_appears: "3-mark conditions question" } ],
    video_script_hooks: { opening_hook: "Your morning rice was sown with the first monsoon rain; the wheat in your roti waited for the winter chill. India's calendar is written in crops.", concept_reveal: "Crops split into food grains, cash crops and horticulture, and follow three seasons — rabi (winter), kharif (monsoon) and zaid (summer)." },
