  sst_ch9_tech_reforms: {
    visual_description: "A timeline-style concept-web showing the Green Revolution package (HYV seeds, irrigation, fertilisers) feeding into institutional reforms (land reform, MSP, Kisan Credit) and government schemes.",
    svg_diagrams: [svg("sst_ch9_tech_reforms_diagram", "Green Revolution & Reforms", `<text x="20" y="26" font-weight="bold">Tech &amp; Institutional Reforms</text><rect x="20" y="45" width="160" height="55" fill="none" stroke="black"/><text x="30" y="65" font-size="11">Technical: HYV seeds,</text><text x="30" y="82" font-size="11">irrigation, fertilisers,</text><text x="30" y="96" font-size="11">tractors (Green Rev.)</text><line x1="180" y1="72" x2="230" y2="72" stroke="black"/><rect x="230" y="45" width="170" height="55" fill="none" stroke="black"/><text x="240" y="65" font-size="11">Institutional: land reform,</text><text x="240" y="82" font-size="11">consolidation, abolition</text><text x="240" y="96" font-size="11">of zamindari</text><rect x="20" y="120" width="380" height="45" fill="none" stroke="black"/><text x="30" y="140" font-size="11">Govt support: MSP, buffer stock,</text><text x="30" y="158" font-size="11">Kisan Credit Card, crop insurance, Gramin Banks</text>`)],
    when_to_use_this_method: { use_this_when: ["Explain the Green Revolution and its inputs (HYV seeds, chemical fertilisers, irrigation)", "List institutional vs technical reforms", "Government measures: MSP, buffer stock, Kisan Credit Card, PM crop insurance"], use_other_when: ["Naming crops/seasons — use Major Crops", "Defining types of farming — use Agriculture Types"] },
    edge_cases: [ { case: "Green Revolution benefited all regions equally", value: "It was concentrated in Punjab, Haryana and western UP; many areas with traditional farming were left untouched, widening regional disparity", reasoning: "HYV package needed assured irrigation and capital that only some regions had", where_it_appears: "HOTS / 5-mark value question" }, { case: "MSP and buffer stock are the same thing", value: "MSP is the minimum announced price at which the government buys crops to protect farmers; buffer stock is the food grain reserve the government keeps for distribution and price control", reasoning: "MSP is a price guarantee; buffer stock is a stored quantity", where_it_appears: "1-mark distinguish" } ],
    video_script_hooks: { opening_hook: "In the 1960s India was importing grain to survive famine; a decade later it was self-sufficient in wheat. The miracle had a name — the Green Revolution.", concept_reveal: "Modern farming came from two reform streams: technical inputs (HYV seeds, irrigation, fertilisers) and institutional support (land reform, MSP, credit)." },
  },
