    when_to_use_this_method: { use_this_when: ["Three-way classification: metallic / non-metallic / energy minerals", "Why and how minerals must be conserved", "Defining a mineral and modes of occurrence (veins, beds, alluvial placer)"], use_other_when: ["Specifically iron-ore belts and ferrous/non-ferrous facts — use Minerals", "Energy generation sources (solar/nuclear) — use Energy Resources"] },
