    visual_description: "A concept-web of India's transport networks branching into roadways (NH, Golden Quadrilateral), railways, pipelines, waterways and airways.",
    svg_diagrams: [svg("sst_ch12_transport_diagram", "Transport Networks", `<text x="20" y="26" font-weight="bold">Transport in India</text><line x1="120" y1="38" x2="50" y2="65" stroke="black"/><line x1="120" y1="38" x2="170" y2="65" stroke="black"/><line x1="120" y1="38" x2="300" y2="65" stroke="black"/><line x1="120" y1="38" x2="420" y2="65" stroke="black"/><line x1="120" y1="38" x2="520" y2="65" stroke="black"/><text x="20" y="85" font-size="11">Roads:</text><text x="20" y="102" font-size="10">NH, Golden Quad.</text><text x="150" y="85" font-size="11">Rail</text><text x="270" y="85" font-size="11">Pipelines</text><text x="270" y="102" font-size="10">crude/gas</text><text x="400" y="85" font-size="11">Waterways</text><text x="500" y="85" font-size="11">Airways</text><text x="20" y="155" font-size="10">Golden Quadrilateral links Delhi-Mumbai-Chennai-Kolkata</text>`)],
    when_to_use_this_method: { use_this_when: ["Compare modes of transport (roads vs railways vs pipelines etc.)", "Facts on Golden Quadrilateral, NH/SH classification, National Waterways", "Map-marking major roads, rail zones, airports or waterways"], use_other_when: ["Exports/imports and ports — use International Trade", "Postal/telecom/media — use Communication"] },
    edge_cases: [ { case: "Golden Quadrilateral and North-South & East-West corridors are the same project", value: "Golden Quadrilateral super-highways link Delhi, Mumbai, Chennai and Kolkata; the North-South corridor links Srinagar to Kanniyakumari and the East-West corridor links Silchar to Porbandar", reasoning: "GQ is the four-metro quadrilateral; the corridors are the cross routes", where_it_appears: "MCQ / 3-mark" }, { case: "National Highways are maintained by State governments", value: "National Highways are laid and maintained by the CPWD/NHAI; State Highways are maintained by State governments", reasoning: "NHs link state capitals and major cities and are a central responsibility", where_it_appears: "1-mark fact" } ],
    video_script_hooks: { opening_hook: "A truck on the Golden Quadrilateral, a train through a mountain tunnel, oil silently flowing through a buried pipe — India moves on a web you rarely see whole.", concept_reveal: "India's lifelines are five transport modes — roadways (NH and the Golden Quadrilateral), railways, pipelines, waterways and airways — each suited to different goods and distances." },
