    svg_diagrams: [svg("sst_ch14_sectors_diagram", "Three Sectors of the Economy", `<text x="20" y="26" font-weight="bold">Primary - Secondary - Tertiary</text><rect x="20" y="50" width="150" height="100" fill="#dcfce7" stroke="#166534"/><text x="40" y="72" font-size="12" font-weight="bold">Primary</text><text x="30" y="95" font-size="11">Farming, mining,</text><text x="30" y="112" font-size="11">fishing (nature)</text><rect x="200" y="50" width="150" height="100" fill="#fef9c3" stroke="#854d0e"/><text x="225" y="72" font-size="12" font-weight="bold">Secondary</text><text x="210" y="95" font-size="11">Manufacturing,</text><text x="210" y="112" font-size="11">factories (industry)</text><rect x="380" y="50" width="160" height="100" fill="#dbeafe" stroke="#1e40af"/><text x="405" y="72" font-size="12" font-weight="bold">Tertiary</text><text x="390" y="95" font-size="11">Services: transport,</text><text x="390" y="112" font-size="11">banking, trade</text><line x1="170" y1="100" x2="200" y2="100" stroke="#475569"/><line x1="350" y1="100" x2="380" y2="100" stroke="#475569"/>`)],
    when_to_use_this_method: { use_this_when: ["Classify-the-activity questions (sort examples into primary/secondary/tertiary)", "Questions on how GDP share shifted to tertiary while most workers stayed in primary", "Numerical / graph reading of GDP and employment shares by sector"], use_other_when: ["Questions on organised vs unorganised or unemployment — use the Employment topic"] },
